import sys
class Solution:
    def subtreeInversionSum(self, edges, nums, k):
        sys.setrecursionlimit(300000)
        n = len(nums)
        g = [[] for _ in range(n)]
        for u, v in edges:
            g[u].append(v)
            g[v].append(u)
        from functools import lru_cache
        # build children/parent first to make the graph rooted
        parent = [-1] * n
        children = [[] for _ in range(n)]
        seen = [False] * n
        seen[0] = True
        stack = [0]
        while stack:
            u = stack.pop()
            for w in g[u]:
                if not seen[w]:
                    seen[w] = True
                    parent[w] = u
                    children[u].append(w)
                    stack.append(w)
        @lru_cache(maxsize=None)
        def dp(u, sign, d):
            a = sign * nums[u]
            dd = d + 1 if d + 1 < k else k
            for c in children[u]:
                a += dp(c, sign, dd)
            best = a
            if d >= k:
                b = -sign * nums[u]
                for c in children[u]:
                    b += dp(c, -sign, 1)
                if b > best:
                    best = b
            return best
        return dp(0, 1, k)

