        parent = [-1] * n
        children = [[] for _ in range(n)]
        order = []
        seen = [False] * n
        seen[0] = True
        stack = [0]
        while stack:
            u = stack.pop()
            order.append(u)
            for w in g[u]:
                if not seen[w]:
                    seen[w] = True
                    parent[w] = u
                    children[u].append(w)
                    stack.append(w)
        dp = [None] * n
        for u in reversed(order):
            tbl = [[0] * (k + 1) for _ in range(2)]
            for s in range(2):
                sign = 1 if s == 0 else -1
                for d in range(1, k + 1):
                    a = sign * nums[u]
                    dd = d + 1 if d + 1 < k else k
                    for c in children[u]:
                        a += dp[c][s][dd]
                    best = a
                    if d >= k:
                        b = -sign * nums[u]
                        ns = 1 - s
                        for c in children[u]:
                            b += dp[c][ns][1]
                        if b > best:
                            best = b
                    tbl[s][d] = best
            dp[u] = tbl
        return dp[0][0][k]

