var subtreeInversionSum = function(edges, nums, k) {
    const n = nums.length;
    const g = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) { g[u].push(v); g[v].push(u); }
    const parent = new Array(n).fill(-1);
    const children = Array.from({ length: n }, () => []);
    const order = [];
    const seen = new Array(n).fill(false);
    seen[0] = true;
    const stk = [0];
    while (stk.length) {
        const u = stk.pop();
        order.push(u);
        for (const w of g[u]) {
            if (!seen[w]) { seen[w] = true; parent[w] = u; children[u].push(w); stk.push(w); }
        }
    }
    const dp = new Array(n);
    for (let oi = order.length - 1; oi >= 0; oi--) {
        const u = order[oi];
        const tbl = [new Array(k + 1).fill(0), new Array(k + 1).fill(0)];
        for (let s = 0; s < 2; s++) {
            const sign = s === 0 ? 1 : -1;
            for (let d = 1; d <= k; d++) {
                let a = sign * nums[u];
                const dd = d + 1 < k ? d + 1 : k;
                for (const c of children[u]) a += dp[c][s][dd];
                let best = a;
                if (d >= k) {
                    let b = -sign * nums[u];
                    const ns = 1 - s;
                    for (const c of children[u]) b += dp[c][ns][1];
                    if (b > best) best = b;
                }
                tbl[s][d] = best;
            }
        }
        dp[u] = tbl;
    }
    return dp[0][0][k];
};
